SELECT count(*) FROM company_type, movie_companies, company_name, title, movie_info, info_type, movie_keyword, cast_info WHERE movie_companies.company_type_id = company_type.id AND movie_companies.company_id = company_name.id AND movie_companies.movie_id = title.id AND movie_info.movie_id = title.id AND movie_info.info_type_id = info_type.id AND movie_keyword.movie_id = title.id AND cast_info.movie_id = title.id;